"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[97620],{24504:e=>{e.exports=JSON.parse('{"tag":{"label":"breeds","permalink":"/docs/tags/breeds","allTagsPath":"/docs/tags","count":7,"items":[{"id":"Chinchillas/breeds-and-genetics/know-your-chinchilla-breeds","title":"Know Your Chinchilla Breeds","description":"An overview of chinchilla species and the wide variety of color mutations found in pet chinchillas.","permalink":"/docs/Chinchillas/breeds-and-genetics/know-your-chinchilla-breeds"},{"id":"Gerbils/breeds-and-genetics/know-your-gerbil-breeds","title":"Know Your Gerbil Breeds","description":"An overview of the two species of gerbils commonly kept as pets, and the wide variety of coat colors found in Mongolian gerbils.","permalink":"/docs/Gerbils/breeds-and-genetics/know-your-gerbil-breeds"},{"id":"guinea-pigs/breeds-and-genetics/know-your-guinea-pig-breeds","title":"Know Your Guinea Pig Breeds","description":"From the sleek and smooth to the curly and long-haired, guinea pigs come in a wonderful variety of breeds, each with its own unique look and grooming needs. While personality is individual, some...","permalink":"/docs/guinea-pigs/breeds-and-genetics/know-your-guinea-pig-breeds"},{"id":"Hamsters/breeds-and-genetics/know-your-hamster-breeds","title":"Know Your Hamster Breeds","description":"An overview of the five hamster species commonly kept as pets, with their key traits, size, and care considerations.","permalink":"/docs/Hamsters/breeds-and-genetics/know-your-hamster-breeds"},{"id":"Mice/breeds-and-genetics/know-your-mouse-breeds","title":"Know Your Mouse Breeds","description":"An overview of the varieties of fancy mice, including coat types, colors, and markings recognized by the American Fancy Rat and Mouse Association.","permalink":"/docs/Mice/breeds-and-genetics/know-your-mouse-breeds"},{"id":"guinea-pigs/breeds-and-genetics/coat-color-genetics","title":"Understanding Guinea Pig Coat Color Genetics","description":"Guinea pigs are known for their stunning diversity of coat colors and patterns, from solid black to intricate brindles and dalmatians. This variety isn\'t random; it\'s the result of a fascinating and complex world of genetics. Understanding the basics of coat color inheritance is not only interesting for curious owners but is also critical for responsible breeding and rescue advocacy to prevent serious genetic health problems.","permalink":"/docs/guinea-pigs/breeds-and-genetics/coat-color-genetics"},{"id":"guinea-pigs/breeds-and-genetics/hairless-skinny-pigs","title":"What to Know about Hairless or \\"Skinny\\" Pigs","description":"Hairless guinea pigs, most commonly known as \\"Skinny Pigs,\\" are a unique and increasingly popular variety of cavy. Their striking appearance, lacking the typical fluffy coat, makes them stand out, but it also means they have specialized care requirements that potential owners must be prepared to meet. Understanding their unique needs is essential to providing them with a healthy and happy life.","permalink":"/docs/guinea-pigs/breeds-and-genetics/hairless-skinny-pigs"}],"unlisted":false}}')}}]);